import React, { useState } from 'react';
import { useSupabase } from '../context/SupabaseContext';

const inputStyle = {
  width: '100%',
  padding: '10px 14px',
  background: 'rgba(255,255,255,0.06)',
  border: '1px solid rgba(255,255,255,0.1)',
  borderRadius: 8,
  fontSize: 14,
  outline: 'none',
  fontFamily: 'inherit',
  boxSizing: 'border-box',
  color: '#fff',
};

const labelStyle = {
  fontSize: 12,
  fontWeight: 600,
  color: 'rgba(255,255,255,0.45)',
  textTransform: 'uppercase',
  letterSpacing: '0.4px',
  display: 'block',
  marginBottom: 5,
};

const btnStyle = (loading) => ({
  padding: '12px',
  background: '#1D4ED8',
  color: '#fff',
  border: 'none',
  borderRadius: 9,
  fontSize: 14,
  fontWeight: 700,
  cursor: loading ? 'not-allowed' : 'pointer',
  fontFamily: 'inherit',
  opacity: loading ? 0.7 : 1,
  marginTop: 2,
  width: '100%',
});

export default function LoginPage() {
  const { client } = useSupabase();
  const [view, setView]         = useState('login');
  const [identifier, setIdentifier] = useState(''); // email or username
  const [password, setPassword] = useState('');
  const [name, setName]         = useState('');
  const [loading, setLoading]   = useState(false);
  const [error, setError]       = useState('');
  const [success, setSuccess]   = useState('');

  const reset = () => { setError(''); setSuccess(''); };

  // ── Resolve identifier: if it has no '@', look up email by username ──
  const resolveEmail = async (raw) => {
    const trimmed = raw.trim();
    if (trimmed.includes('@')) return trimmed;

    // username lookup via DB function
    const { data, error: rpcErr } = await client
      .rpc('get_email_by_username', { p_username: trimmed });

    if (rpcErr || !data) return null;
    return data;
  };

  const handleLogin = async e => {
    e.preventDefault();
    setLoading(true);
    reset();

    const email = await resolveEmail(identifier);
    if (!email) {
      setError('Username not found. Please try your email instead.');
      setLoading(false);
      return;
    }

    const { error: err } = await client.auth.signInWithPassword({ email, password });
    if (err) {
      // Give friendlier messages
      if (err.message.toLowerCase().includes('invalid login')) {
        setError('Incorrect email/username or password.');
      } else if (err.message.toLowerCase().includes('email not confirmed')) {
        setError('Please confirm your email address before signing in.');
      } else {
        setError(err.message);
      }
    }
    setLoading(false);
  };

  const handleForgot = async e => {
    e.preventDefault();
    setLoading(true);
    reset();

    const email = await resolveEmail(identifier);
    if (!email) {
      setError('Username not found. Please enter your email instead.');
      setLoading(false);
      return;
    }

    const { error: err } = await client.auth.resetPasswordForEmail(email, {
      redirectTo: window.location.origin + window.location.pathname,
    });
    setLoading(false);
    if (err) { setError(err.message); return; }
    setSuccess('Password reset email sent! Check your inbox.');
  };

  const handleRequest = async e => {
    e.preventDefault();
    setLoading(true);
    reset();

    const emailVal = identifier.trim();

    // Must be a real email for signup
    if (!emailVal.includes('@')) {
      setError('Please enter a valid email address to request access.');
      setLoading(false);
      return;
    }

    const { data, error: err } = await client.auth.signUp({
      email: emailVal,
      password,
      options: { data: { full_name: name } },
    });

    setLoading(false);

    if (err) {
      if (err.message.toLowerCase().includes('already registered')) {
        setError('This email is already registered. Try signing in instead.');
      } else {
        setError(err.message);
      }
      return;
    }

    // Supabase signUp can succeed but return no session if email confirm is on
    if (data?.user && !data?.session) {
      setSuccess('Check your email to confirm your address, then an admin will approve your account.');
    } else {
      setSuccess('Access request submitted! An administrator will approve your account.');
    }

    setView('login');
    setIdentifier('');
    setPassword('');
    setName('');
  };

  return (
    <div style={{ minHeight:'100vh', background:'#0F172A', display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', fontFamily:'Inter, sans-serif', padding:16 }}>
      <div style={{ width:'100%', maxWidth:420 }}>

        {/* Card */}
        <div style={{ background:'#1E293B', border:'1px solid rgba(255,255,255,0.08)', borderRadius:18, padding:'44px 44px 36px', boxShadow:'0 24px 48px rgba(0,0,0,0.4)' }}>

          {/* Logo */}
          <div style={{ display:'flex', alignItems:'center', gap:12, marginBottom:30 }}>
            <div style={{ width:40, height:40, borderRadius:11, background:'#1D4ED8', display:'flex', alignItems:'center', justifyContent:'center', fontSize:22, flexShrink:0 }}>🚛</div>
            <div>
              <div style={{ fontWeight:800, fontSize:16, color:'#fff' }}>FleetMS</div>
              <div style={{ fontSize:11, color:'rgba(255,255,255,0.35)', letterSpacing:1, textTransform:'uppercase' }}>Fleet Management</div>
            </div>
          </div>

          {/* ── LOGIN ── */}
          {view === 'login' && (
            <>
              <h2 style={{ margin:'0 0 4px', fontSize:22, fontWeight:800, color:'#fff' }}>Welcome back</h2>
              <p style={{ margin:'0 0 24px', fontSize:13, color:'rgba(255,255,255,0.4)' }}>Sign in to manage your fleet</p>

              {success && (
                <div style={{ margin:'0 0 14px', padding:'10px 14px', background:'rgba(22,163,74,0.15)', border:'1px solid rgba(22,163,74,0.4)', borderRadius:8, fontSize:13, color:'#86EFAC', fontWeight:500 }}>
                  {success}
                </div>
              )}

              <form onSubmit={handleLogin} style={{ display:'flex', flexDirection:'column', gap:14 }}>
                <div>
                  <label style={labelStyle}>Email or Username</label>
                  <input
                    type="text"
                    value={identifier}
                    onChange={e => setIdentifier(e.target.value)}
                    required
                    autoComplete="username"
                    style={inputStyle}
                    placeholder="you@company.com or username"
                  />
                </div>
                <div>
                  <label style={labelStyle}>Password</label>
                  <input
                    type="password"
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                    required
                    autoComplete="current-password"
                    style={inputStyle}
                    placeholder="••••••••"
                  />
                </div>

                {error && (
                  <p style={{ margin:0, fontSize:13, color:'#FCA5A5', background:'rgba(220,38,38,0.12)', padding:'9px 12px', borderRadius:7, border:'1px solid rgba(220,38,38,0.3)' }}>
                    {error}
                  </p>
                )}

                <button type="submit" disabled={loading} style={btnStyle(loading)}>
                  {loading ? 'Signing in…' : 'Sign In'}
                </button>
              </form>

              <div style={{ display:'flex', justifyContent:'center', gap:16, marginTop:18 }}>
                <button onClick={() => { setView('forgot'); reset(); }} style={{ background:'none', border:'none', fontSize:12, color:'rgba(255,255,255,0.4)', cursor:'pointer', fontFamily:'inherit', textDecoration:'underline' }}>
                  Forgot password?
                </button>
                <button onClick={() => { setView('request'); reset(); }} style={{ background:'none', border:'none', fontSize:12, color:'#60A5FA', cursor:'pointer', fontFamily:'inherit', textDecoration:'underline', fontWeight:600 }}>
                  Request access
                </button>
              </div>
            </>
          )}

          {/* ── FORGOT PASSWORD ── */}
          {view === 'forgot' && (
            <>
              <button onClick={() => { setView('login'); reset(); }} style={{ background:'none', border:'none', fontSize:12, color:'rgba(255,255,255,0.4)', cursor:'pointer', fontFamily:'inherit', marginBottom:16, padding:0 }}>
                ← Back to sign in
              </button>
              <h2 style={{ margin:'0 0 4px', fontSize:20, fontWeight:800, color:'#fff' }}>Reset password</h2>
              <p style={{ margin:'0 0 24px', fontSize:13, color:'rgba(255,255,255,0.4)' }}>Enter your email or username and we'll send a reset link</p>

              {success && (
                <div style={{ margin:'0 0 14px', padding:'10px 14px', background:'rgba(22,163,74,0.15)', border:'1px solid rgba(22,163,74,0.4)', borderRadius:8, fontSize:13, color:'#86EFAC' }}>
                  {success}
                </div>
              )}

              <form onSubmit={handleForgot} style={{ display:'flex', flexDirection:'column', gap:14 }}>
                <div>
                  <label style={labelStyle}>Email or Username</label>
                  <input
                    type="text"
                    value={identifier}
                    onChange={e => setIdentifier(e.target.value)}
                    required
                    autoFocus
                    style={inputStyle}
                    placeholder="you@company.com or username"
                  />
                </div>

                {error && (
                  <p style={{ margin:0, fontSize:13, color:'#FCA5A5', background:'rgba(220,38,38,0.12)', padding:'9px 12px', borderRadius:7 }}>
                    {error}
                  </p>
                )}

                <button type="submit" disabled={loading} style={btnStyle(loading)}>
                  {loading ? 'Sending…' : 'Send Reset Link'}
                </button>
              </form>
            </>
          )}

          {/* ── REQUEST ACCESS ── */}
          {view === 'request' && (
            <>
              <button onClick={() => { setView('login'); reset(); }} style={{ background:'none', border:'none', fontSize:12, color:'rgba(255,255,255,0.4)', cursor:'pointer', fontFamily:'inherit', marginBottom:16, padding:0 }}>
                ← Back to sign in
              </button>
              <h2 style={{ margin:'0 0 4px', fontSize:20, fontWeight:800, color:'#fff' }}>Request Access</h2>
              <p style={{ margin:'0 0 16px', fontSize:13, color:'rgba(255,255,255,0.4)' }}>Submit a request — an admin will approve your account</p>

              <div style={{ background:'rgba(251,191,36,0.1)', border:'1px solid rgba(251,191,36,0.25)', borderRadius:8, padding:'10px 14px', fontSize:12, color:'#FCD34D', marginBottom:18 }}>
                ℹ️ Your account will be pending until an administrator approves it.
              </div>

              {error && (
                <p style={{ margin:'0 0 12px', fontSize:13, color:'#FCA5A5', background:'rgba(220,38,38,0.12)', padding:'9px 12px', borderRadius:7 }}>
                  {error}
                </p>
              )}

              <form onSubmit={handleRequest} style={{ display:'flex', flexDirection:'column', gap:14 }}>
                <div>
                  <label style={labelStyle}>Full Name</label>
                  <input
                    type="text"
                    value={name}
                    onChange={e => setName(e.target.value)}
                    required
                    style={inputStyle}
                    placeholder="Your full name"
                  />
                </div>
                <div>
                  <label style={labelStyle}>Email</label>
                  <input
                    type="email"
                    value={identifier}
                    onChange={e => setIdentifier(e.target.value)}
                    required
                    autoComplete="email"
                    style={inputStyle}
                    placeholder="you@company.com"
                  />
                </div>
                <div>
                  <label style={labelStyle}>Password</label>
                  <input
                    type="password"
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                    required
                    minLength={6}
                    autoComplete="new-password"
                    style={inputStyle}
                    placeholder="Choose a password (min 6 chars)"
                  />
                </div>

                <button type="submit" disabled={loading} style={btnStyle(loading)}>
                  {loading ? 'Submitting…' : 'Submit Request'}
                </button>
              </form>
            </>
          )}
        </div>

        {/* Footer */}
        <div style={{ textAlign:'center', marginTop:20 }}>
          <a href="https://messaging-service.co.tz/" target="_blank" rel="noopener noreferrer"
            style={{ fontSize:12, color:'#60A5FA', fontWeight:700, textDecoration:'none' }}>Staff-SMS</a>
          <span style={{ fontSize:12, color:'rgba(255,255,255,0.3)' }}> · FleetMS © {new Date().getFullYear()}</span>
        </div>
      </div>
    </div>
  );
}
